const t=JSON.parse('{"key":"v-64f1e374","path":"/JavaWeb/19.JSTL_EL-practice.html","title":"JSTL+El练习（数据展示案例）","lang":"zh-CN","frontmatter":{"title":"JSTL+El练习（数据展示案例）","order":19,"tag":"JSTL","category":"JavaWEB","description":"1. 需求 在request域中有一个存有User对象的List集合。需要使用jstl+el将list集合数据展示到jsp页面的表格table中。 2. 实现代码 实现代码只展示jsp页面的代码，另外需要的User类就是封装用户数据的JavaBean这里不进行展示。 &lt;%@ page import=\\"io.gitee.hek97.domain.User\\" %&gt; &lt;%@ page import=\\"java.util.List\\" %&gt; &lt;%@ page import=\\"java.util.ArrayList\\" %&gt; &lt;%@ page contentType=\\"text/html;charset=UTF-8\\" language=\\"java\\" %&gt; &lt;%--1.导入jstl的相关jar包并引入jstl标签库--%&gt; &lt;%@ taglib prefix=\\"c\\" uri=\\"http://java.sun.com/jsp/jstl/core\\" %&gt; &lt;html&gt; &lt;head&gt; &lt;title&gt;JSP+JSTL+EL获取User对象的值&lt;/title&gt; &lt;/head&gt; &lt;body&gt; &lt;% List&lt;User&gt; users = new ArrayList&lt;&gt;(); //第一名人员信息 User user1 = new User(); user1.setId(1001); user1.setUsername(\\"张三\\"); user1.setPassword(\\"123\\"); //第二名人员信息 User user2 = new User(); user2.setId(1002); user2.setUsername(\\"李四\\"); user2.setPassword(\\"456\\"); //将user添加到List集合中 users.add(user1); users.add(user2); //将信息存储到共享域中 request.setAttribute(\\"users\\",users); %&gt; &lt;%--视图V:表格展示--%&gt; &lt;table border=\\"1\\"&gt; &lt;%--表头--%&gt; &lt;tr&gt; &lt;th&gt;索引&lt;/th&gt; &lt;th&gt;循环次数&lt;/th&gt; &lt;th&gt;用户id&lt;/th&gt; &lt;th&gt;用户名&lt;/th&gt; &lt;th&gt;用户密码&lt;/th&gt; &lt;/tr&gt; &lt;%--表体--%&gt; &lt;%--遍历users集合容器--%&gt; &lt;c:forEach items=\\"${users}\\" var=\\"user\\" varStatus=\\"s\\"&gt; &lt;tr&gt; &lt;td&gt;${s.index}&lt;/td&gt; &lt;td&gt;${s.count}&lt;/td&gt; &lt;td&gt;${user.id}&lt;/td&gt; &lt;td&gt;${user.username}&lt;/td&gt; &lt;td&gt;${user.password}&lt;/td&gt; &lt;/tr&gt; &lt;/c:forEach&gt; &lt;/table&gt; &lt;/body&gt; &lt;/html&gt;","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/JavaWeb/19.JSTL_EL-practice.html"}],["meta",{"property":"og:site_name","content":"专业治头秃"}],["meta",{"property":"og:title","content":"JSTL+El练习（数据展示案例）"}],["meta",{"property":"og:description","content":"1. 需求 在request域中有一个存有User对象的List集合。需要使用jstl+el将list集合数据展示到jsp页面的表格table中。 2. 实现代码 实现代码只展示jsp页面的代码，另外需要的User类就是封装用户数据的JavaBean这里不进行展示。 &lt;%@ page import=\\"io.gitee.hek97.domain.User\\" %&gt; &lt;%@ page import=\\"java.util.List\\" %&gt; &lt;%@ page import=\\"java.util.ArrayList\\" %&gt; &lt;%@ page contentType=\\"text/html;charset=UTF-8\\" language=\\"java\\" %&gt; &lt;%--1.导入jstl的相关jar包并引入jstl标签库--%&gt; &lt;%@ taglib prefix=\\"c\\" uri=\\"http://java.sun.com/jsp/jstl/core\\" %&gt; &lt;html&gt; &lt;head&gt; &lt;title&gt;JSP+JSTL+EL获取User对象的值&lt;/title&gt; &lt;/head&gt; &lt;body&gt; &lt;% List&lt;User&gt; users = new ArrayList&lt;&gt;(); //第一名人员信息 User user1 = new User(); user1.setId(1001); user1.setUsername(\\"张三\\"); user1.setPassword(\\"123\\"); //第二名人员信息 User user2 = new User(); user2.setId(1002); user2.setUsername(\\"李四\\"); user2.setPassword(\\"456\\"); //将user添加到List集合中 users.add(user1); users.add(user2); //将信息存储到共享域中 request.setAttribute(\\"users\\",users); %&gt; &lt;%--视图V:表格展示--%&gt; &lt;table border=\\"1\\"&gt; &lt;%--表头--%&gt; &lt;tr&gt; &lt;th&gt;索引&lt;/th&gt; &lt;th&gt;循环次数&lt;/th&gt; &lt;th&gt;用户id&lt;/th&gt; &lt;th&gt;用户名&lt;/th&gt; &lt;th&gt;用户密码&lt;/th&gt; &lt;/tr&gt; &lt;%--表体--%&gt; &lt;%--遍历users集合容器--%&gt; &lt;c:forEach items=\\"${users}\\" var=\\"user\\" varStatus=\\"s\\"&gt; &lt;tr&gt; &lt;td&gt;${s.index}&lt;/td&gt; &lt;td&gt;${s.count}&lt;/td&gt; &lt;td&gt;${user.id}&lt;/td&gt; &lt;td&gt;${user.username}&lt;/td&gt; &lt;td&gt;${user.password}&lt;/td&gt; &lt;/tr&gt; &lt;/c:forEach&gt; &lt;/table&gt; &lt;/body&gt; &lt;/html&gt;"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-04-04T10:28:12.000Z"}],["meta",{"property":"article:tag","content":"JSTL"}],["meta",{"property":"article:modified_time","content":"2023-04-04T10:28:12.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"JSTL+El练习（数据展示案例）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-04-04T10:28:12.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"1. 需求","slug":"_1-需求","link":"#_1-需求","children":[]},{"level":2,"title":"2. 实现代码","slug":"_2-实现代码","link":"#_2-实现代码","children":[]},{"level":2,"title":"3. 效果展示","slug":"_3-效果展示","link":"#_3-效果展示","children":[]}],"git":{"createdTime":1680604092000,"updatedTime":1680604092000,"contributors":[{"name":"hk","email":"hek97@qq.com","commits":1}]},"readingTime":{"minutes":1.07,"words":320},"filePathRelative":"JavaWeb/19.JSTL+EL-practice.md","localizedDate":"2023年4月4日","excerpt":"<h2> 1. 需求</h2>\\n<p>在request域中有一个存有User对象的List集合。需要使用<code>jstl+el</code>将list集合数据展示到jsp页面的表格table中。</p>\\n<h2> 2. 实现代码</h2>\\n<p>实现代码只展示jsp页面的代码，另外需要的User类就是封装用户数据的JavaBean这里不进行展示。</p>\\n<div class=\\"language-jsp line-numbers-mode\\" data-ext=\\"jsp\\"><pre class=\\"language-jsp\\"><code>&lt;%@ page import=\\"io.gitee.hek97.domain.User\\" %&gt;\\n&lt;%@ page import=\\"java.util.List\\" %&gt;\\n&lt;%@ page import=\\"java.util.ArrayList\\" %&gt;\\n&lt;%@ page contentType=\\"text/html;charset=UTF-8\\" language=\\"java\\" %&gt;\\n\\n&lt;%--1.导入jstl的相关jar包并引入jstl标签库--%&gt;\\n&lt;%@ taglib prefix=\\"c\\" uri=\\"http://java.sun.com/jsp/jstl/core\\" %&gt;\\n\\n&lt;html&gt;\\n&lt;head&gt;\\n  &lt;title&gt;JSP+JSTL+EL获取User对象的值&lt;/title&gt;\\n&lt;/head&gt;\\n&lt;body&gt;\\n&lt;%\\n  List&lt;User&gt; users = new ArrayList&lt;&gt;();\\n  //第一名人员信息\\n  User user1 = new User();\\n  user1.setId(1001);\\n  user1.setUsername(\\"张三\\");\\n  user1.setPassword(\\"123\\");\\n  //第二名人员信息\\n  User user2 = new User();\\n  user2.setId(1002);\\n  user2.setUsername(\\"李四\\");\\n  user2.setPassword(\\"456\\");\\n  //将user添加到List集合中\\n  users.add(user1);\\n  users.add(user2);\\n  //将信息存储到共享域中\\n  request.setAttribute(\\"users\\",users);\\n%&gt;\\n&lt;%--视图V:表格展示--%&gt;\\n&lt;table border=\\"1\\"&gt;\\n &lt;%--表头--%&gt;\\n  &lt;tr&gt;\\n    &lt;th&gt;索引&lt;/th&gt;\\n    &lt;th&gt;循环次数&lt;/th&gt;\\n    &lt;th&gt;用户id&lt;/th&gt;\\n    &lt;th&gt;用户名&lt;/th&gt;\\n    &lt;th&gt;用户密码&lt;/th&gt;\\n  &lt;/tr&gt;\\n&lt;%--表体--%&gt;\\n  &lt;%--遍历users集合容器--%&gt;\\n  &lt;c:forEach items=\\"${users}\\" var=\\"user\\" varStatus=\\"s\\"&gt;\\n    &lt;tr&gt;\\n      &lt;td&gt;${s.index}&lt;/td&gt;\\n      &lt;td&gt;${s.count}&lt;/td&gt;\\n      &lt;td&gt;${user.id}&lt;/td&gt;\\n      &lt;td&gt;${user.username}&lt;/td&gt;\\n      &lt;td&gt;${user.password}&lt;/td&gt;\\n    &lt;/tr&gt;\\n  &lt;/c:forEach&gt;\\n&lt;/table&gt;\\n&lt;/body&gt;\\n&lt;/html&gt;\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>","autoDesc":true}');export{t as data};
